{
  "title": "Beginner Guitar Course: Strumming Your Way to Confidence",
  "description": "This course is designed for complete beginners who want to learn the fundamentals of guitar playing while developing skills to impress and connect with others through music.",
  "modules": [
    {
      "id": "module1",
      "title": "Getting Started with Your Guitar",
      "description": "Introduction to the parts of the guitar, how to hold it, basic tuning techniques, and understanding the strings."
    },
    {
      "id": "module2",
      "title": "Basic Chords and Strumming Patterns",
      "description": "Learn essential open chords and simple strumming patterns that will allow you to play popular songs and create a foundation for further learning."
    },
    {
      "id": "module3",
      "title": "Playing Your First Songs",
      "description": "Apply your knowledge of chords and strumming to play easy songs that can help you impress others and build confidence in your playing."
    },
    {
      "id": "module4",
      "title": "Developing Your Style and Confidence",
      "description": "Explore techniques to personalize your playing, including basic fingerpicking and rhythm variations, while focusing on building confidence to perform in front of others."
    }
  ]
}
